JS_CODE = 'const answers = {};\n    const totalQ = 8;\n\n    document.querySelectorAll(\'.quiz-btn\').forEach(btn => {\n      btn.addEventListener(\'click\', function() {\n        const q = parseInt(this.dataset.q);\n        const v = this.dataset.v;\n        answers[q] = v;\n\n        // highlight\n        document.querySelectorAll(`[data-q="${q}"]`).forEach(b => b.classList.remove(\'border-amber-500\',\'bg-amber-100\'));\n        this.classList.add(\'border-amber-500\',\'bg-amber-100\');\n\n        setTimeout(() => {\n          if (q < totalQ) {\n            document.getElementById(`q${q}`).classList.add(\'hidden\');\n            document.getElementById(`q${q+1}`).classList.remove(\'hidden\');\n            const pct = (q / totalQ) * 100;\n            document.getElementById(\'progress-bar\').style.width = pct + \'%\';\n            document.getElementById(\'progress-text\').textContent = `質問 ${q+1} / ${totalQ}`;\n          } else {\n            showResult();\n          }\n        }, 300);\n      });\n    });\n\n    function showResult() {\n      document.getElementById(\'quiz-section\').classList.add(\'hidden\');\n      document.getElementById(\'result-section\').classList.remove(\'hidden\');\n\n      // Calculations\n      const age = parseInt(answers[1]);\n      const savings = parseInt(answers[2]);\n      const monthlyExpense = parseInt(answers[3]);\n      const pension = parseInt(answers[4]);\n      const retireAge = parseInt(answers[5]);\n      const housing = answers[6];\n      const childAid = answers[7];\n      const hobbyCost = answers[8];\n\n      // Years until retirement\n      const yearsToRetire = Math.max(0, retireAge - age);\n      // Assumed savings growth 2% per year\n      const savingsAtRetire = savings * Math.pow(1.02, yearsToRetire);\n\n      // Housing cost addition\n      let housingAdd = 0;\n      if (housing === \'rent-low\') housingAdd = 6;\n      else if (housing === \'rent-high\') housingAdd = 10;\n      else if (housing === \'own-loan\') housingAdd = 4;\n\n      // Hobby cost\n      let hobbyAdd = 0;\n      if (hobbyCost === \'low\') hobbyAdd = 2;\n      else if (hobbyCost === \'mid\') hobbyAdd = 4;\n      else if (hobbyCost === \'high\') hobbyAdd = 6;\n\n      // Child aid one-time cost (万円)\n      const childOneTime = answers[7] === \'none\' ? 0 : answers[7] === \'small\' ? 50 : answers[7] === \'medium\' ? 300 : 700;\n\n      // Monthly living at retirement (老後は現役時の80%と仮定)\n      const retireMonthly = monthlyExpense * 0.8 + housingAdd + hobbyAdd;\n      const retireAnnual = retireMonthly * 12;\n\n      // Pension income annual\n      const pensionAnnual = pension * 12;\n\n      // Annual shortfall\n      const annualShortfall = Math.max(0, retireAnnual - pensionAnnual);\n\n      // Life expectancy 90歳想定\n      const retireYears = 90 - retireAge;\n      const totalNeeded = annualShortfall * retireYears + childOneTime;\n\n      // Gap\n      const gap = totalNeeded - savingsAtRetire;\n\n      const isOK = gap <= 0;\n      const gapAbs = Math.abs(Math.round(gap));\n      const monthlyShortfall = isOK ? 0 : Math.round(gap / retireYears / 12);\n\n      let html = \'\';\n      if (isOK) {\n        html = `\n          <div class="bg-green-50 border-2 border-green-400 rounded-xl p-5 mb-4 text-center">\n            <div class="text-4xl mb-2">✅</div>\n            <h3 class="text-xl font-bold text-green-700">老後資金は充足しています</h3>\n            <p class="text-green-600 mt-2">現在のペースを継続すれば、${retireAge}歳退職・90歳まで安心して生活できます。</p>\n          </div>\n          <div class="grid grid-cols-2 gap-4 mb-4">\n            <div class="bg-amber-50 rounded-xl p-4 text-center">\n              <p class="text-sm text-gray-500">老後月の生活費試算</p>\n              <p class="text-2xl font-bold text-amber-700">${retireMonthly}万円</p>\n            </div>\n            <div class="bg-amber-50 rounded-xl p-4 text-center">\n              <p class="text-sm text-gray-500">年金受給（月）</p>\n              <p class="text-2xl font-bold text-amber-700">${pension}万円</p>\n            </div>\n          </div>\n          <div class="bg-blue-50 rounded-xl p-4 mb-4">\n            <p class="text-sm font-semibold text-blue-700 '
